public int maxScore(int[][] points) {
    int m = points.length, n = points[0].length;
    int[][] dp = new int[m][n];
    dp[0] = points[0];

    for (int r = 1; r < m; r++) {
        for (int c = 0; c < n; c++) {
            int score = points[r][c];
            for (int c_prev = 0; c_prev < n; c_prev++) {
                dp[r][c] = Math.max(dp[r][c], dp[r - 1][c_prev] + score - Math.abs(c - c_prev));
            }
        }
    }

    int max = dp[m - 1][0];
    for (int i = 1; i < n; i++) {
        max = Math.max(max, dp[m - 1][i]);
    }
    return max;
}
```


